// The things `nico-admin-cli ip find` searches.
//
// Why the IpType prefix on everything, you ask? Because:
// > Note that enum values use C++ scoping rules, meaning that enum values are siblings of their
// > type, not children of it.
// Yeah I'm surprised too.
type IpType int32

const (
	IpType_IpTypeStaticDataDhcpServer IpType = 0
	// DEPRECATED: IpTypeStaticDataRouteServer is deprecated in favor
	// of IpTypeRouteServerFromConfigFile and IpTypeRouteServerFromAdminApi.
	IpType_IpTypeStaticDataRouteServer IpType = 1
	IpType_IpTypeResourcePool          IpType = 2
	IpType_IpTypeInstanceAddress       IpType = 3
	IpType_IpTypeMachineAddress        IpType = 4
	IpType_IpTypeBmcIp                 IpType = 5
	IpType_IpTypeLoopbackIp            IpType = 6
	IpType_IpTypeNetworkSegment        IpType = 7
	IpType_IpTypeExploredEndpoint      IpType = 8
	// IpTypeRouteServerFromConfigFile are IPs from the route_servers
	// table that have been synced via the nico-core-api config file
	// at startup (see setup.rs and db_init.rs). Their DB records
	// specifically say their source type is `config_file`.
	IpType_IpTypeRouteServerFromConfigFile IpType = 9
	// IpTypeRouteServerFromAdminApi are IPs from the route_servers
	// table that have been added via nico-admin-cli calls. Their
	// DB records specifically say their source type is `admin`.
	IpType_IpTypeRouteServerFromAdminApi IpType = 10
	IpType_IpTypeDpaInterface            IpType = 11
	// IpTypeStaticBmcIp are BMC IPs that were statically assigned via
	// ExpectedMachine.bmc_ip_address, ExpectedPowerShelf.bmc_ip_address,
	// ExpectedSwitch.bmc_ip_address, or operator static assignment
	// (AllocationType::Static / static-assignments segment), as opposed to
	// a normal DHCP allocation.
	IpType_IpTypeStaticBmcIp IpType = 12
)

